import React from 'react';
import { useCurrentFrame } from 'remotion';
import { PlacementBox } from '../../../lib/canvas';
import { Surface } from '../../../lib/primitives';
import { useTextReveal, useStaggeredEntrance } from '../../../lib/hooks';
import { terminalSchema, type TerminalProps } from './schema';

export { terminalSchema, type TerminalProps };

/**
 * A terminal session: the command types itself after the prompt, a block
 * cursor blinks while typing, then the output lines appear staggered. Built
 * on the glass `Surface`. Calm, deterministic — the cursor blink is keyed off
 * the frame, not a timer.
 *
 * @example
 * <Terminal command="npm run render" output={['done in 4.2s']} />
 */
export const Terminal: React.FC<TerminalProps> = ({
  command, output, prompt, title, chrome, delay, typeSpeed, outputDelay,
  fontFamily, fontSize, width, textColor, promptColor, outputColor, placement,
}) => {
  const frame = useCurrentFrame();
  const shown = useTextReveal({ length: command.length, delay, durationInFrames: typeSpeed });
  const typing = shown < command.length;
  const blinkOn = Math.floor(frame / 15) % 2 === 0;
  const outputAt = useStaggeredEntrance({
    type: 'fade',
    delay: delay + typeSpeed + outputDelay,
    increment: 4,
  });

  return (
    <PlacementBox placement={placement}>
      <Surface variant="glass" width={width} padding={0}>
        {chrome && (
          <div style={{ display: 'flex', alignItems: 'center', gap: 10, padding: '18px 24px', borderBottom: '1px solid #1C1C22' }}>
            <span style={{ width: 18, height: 18, borderRadius: 999, background: 'var(--onda-border-lit, #26262E)' }} />
            <span style={{ width: 18, height: 18, borderRadius: 999, background: 'var(--onda-border-lit, #26262E)' }} />
            <span style={{ width: 18, height: 18, borderRadius: 999, background: 'var(--onda-border-lit, #26262E)' }} />
            {title && <span style={{ marginLeft: 10, color: 'var(--onda-faint, #56565F)', fontFamily, fontSize: fontSize * 0.62, letterSpacing: '0.04em' }}>{title}</span>}
          </div>
        )}
        <div style={{ padding: '28px 36px', fontFamily, fontSize, lineHeight: 1.6 }}>
          <div style={{ whiteSpace: 'pre', color: textColor }}>
            <span style={{ color: promptColor, marginRight: 10 }}>{prompt}</span>
            {command.slice(0, shown)}
            {typing && blinkOn && <span style={{ background: textColor, color: textColor }}>▍</span>}
          </div>
          {output.map((line, i) => (
            <div key={i} style={{ whiteSpace: 'pre', color: outputColor, opacity: outputAt(i).opacity }}>
              {line}
            </div>
          ))}
        </div>
      </Surface>
    </PlacementBox>
  );
};

import { z } from 'zod';
import { placementSchema } from '../../../lib/canvas-schemas';

/** Zod schema for {@link Terminal} props. */
export const terminalSchema = z.object({
  /** Discriminator literal — matches this entry's registry slug. Auto-populated when omitted. */
  kind: z.literal('terminal').default('terminal'),
  /** The command that types itself out after the prompt. */
  command: z.string().default('npx ondajs add code-block'),
  /** Output lines that appear, staggered, once the command finishes typing. */
  output: z.array(z.string()).default(['✓ added code-block', '✓ wrote 4 files']),
  /** The shell prompt glyph. */
  prompt: z.string().default('$'),
  /** Title-bar label. Empty hides it (dots still show if chrome on). */
  title: z.string().default('zsh'),
  /** Show window chrome (dots + title bar). */
  chrome: z.boolean().default(true),
  /** Frames before typing starts. */
  delay: z.number().int().min(0).default(0),
  /** Frames to type the whole command. */
  typeSpeed: z.number().int().min(1).default(30),
  /** Frames after the command finishes before output begins. */
  outputDelay: z.number().int().min(0).default(8),
  /** Monospace font stack. */
  fontFamily: z.string().default('ui-monospace, "SF Mono", Menlo, monospace'),
  /** Font size in px. Sized for a 1080p+ video canvas, not a screen UI. */
  fontSize: z.number().default(48),
  /** Width in px. Fixed by default so the terminal frame is stable while the
   * command types into it — a terminal has a defined size, it doesn't grow
   * character by character. */
  width: z.number().default(1100),
  /** Command text color. */
  textColor: z.string().default('var(--onda-text, #F2F2F4)'),
  /** Prompt glyph color — the earned accent. */
  promptColor: z.string().default('var(--onda-accent, #D96B82)'),
  /** Output line color. */
  outputColor: z.string().default('var(--onda-dim, #8E8E98)'),
  /** Where on the canvas this sits. */
  placement: placementSchema.optional(),
});

/** Inferred props for {@link Terminal}. */
export type TerminalProps = z.infer<typeof terminalSchema>;
